function calculate() {
    const SOLAR_PV_POWER_DENSITY_MW_PER_SQKM = 8; // MW per sq km for utility-scale solar PV
    const WIND_POWER_DENSITY_MW_PER_SQKM = 4; // MW per sq km for typical onshore wind
    const SOLAR_AVG_CAPACITY_FACTOR = 0.20; // 20%
    const WIND_AVG_CAPACITY_FACTOR = 0.35; // 35% (conservative for avg wind speed input)
    const PROJECT_LIFETIME_YEARS = 20; // Years for economic calculations
    const HOURS_IN_YEAR = 8760;

    const {
        solarIrradiance,
        availableLandSolar,
        avgWindSpeed,
        availableLandWind,
        gridInterconnectionCapacity,
        costGridUpgradePerMW,
        avgRenewableLCOE,
        avgRetailElectricityPrice,
        policyIncentivePerMWh,
        annualRegionalDemand
    } = inputs;

    // Input validation (basic guards against non-positive inputs for calculation steps)
    const safeSolarIrradiance = Math.max(0, solarIrradiance);
    const safeAvailableLandSolar = Math.max(0, availableLandSolar);
    const safeAvgWindSpeed = Math.max(0, avgWindSpeed);
    const safeAvailableLandWind = Math.max(0, availableLandWind);
    const safeGridInterconnectionCapacity = Math.max(0, gridInterconnectionCapacity);
    const safeCostGridUpgradePerMW = Math.max(0, costGridUpgradePerMW);
    const safeAvgRenewableLCOE = Math.max(0, avgRenewableLCOE);
    const safeAvgRetailElectricityPrice = Math.max(0, avgRetailElectricityPrice);
    const safePolicyIncentivePerMWh = Math.max(0, policyIncentivePerMWh);
    const safeAnnualRegionalDemand = Math.max(1, annualRegionalDemand); // Demand cannot be zero for percentage calculations

    // --- 1. Calculate Raw Renewable Generation Potential (MW and MWh/year) ---
    // Solar Potential Capacity (MW): Land area * power density
    const solarPotentialCapacityMW = safeAvailableLandSolar * SOLAR_PV_POWER_DENSITY_MW_PER_SQKM;
    const solarPotentialEnergyMWh_yr = solarPotentialCapacityMW * HOURS_IN_YEAR * SOLAR_AVG_CAPACITY_FACTOR;

    // Wind Potential Capacity (MW): Land area * power density. Note: avgWindSpeed is considered in the assumed WIND_AVG_CAPACITY_FACTOR.
    // More complex models would use avgWindSpeed for specific turbine power curves, but for this config, power density + CF is a reasonable abstraction.
    const windPotentialCapacityMW = safeAvailableLandWind * WIND_POWER_DENSITY_MW_PER_SQKM;
    const windPotentialEnergyMWh_yr = windPotentialCapacityMW * HOURS_IN_YEAR * WIND_AVG_CAPACITY_FACTOR;

    const totalRenewablePotentialMW = solarPotentialCapacityMW + windPotentialCapacityMW;
    const totalRenewablePotentialEnergyMWh_yr = solarPotentialEnergyMWh_yr + windPotentialEnergyMWh_yr;

    // --- 2. Determine Maximum Grid Integration Capacity (MW) ---
    // The actual capacity integrated is limited by both physical renewable potential and grid's ability to handle it.
    let maxGridIntegrationMW = safeGridInterconnectionCapacity;
    let upgradeCostAnnualized = 0;

    // Evaluate if it's economically viable to upgrade the grid to integrate more renewables.
    // A simplified viability check: if the market price + incentive exceeds the LCOE, it's generally viable.
    const economicViabilityPerMWh = safeAvgRetailElectricityPrice + safePolicyIncentivePerMWh - safeAvgRenewableLCOE;

    // If there's a positive economic incentive and the grid is a bottleneck, consider upgrading.
    if (economicViabilityPerMWh > 0 && totalRenewablePotentialMW > safeGridInterconnectionCapacity) {
        const requiredUpgradeMW = Math.max(0, totalRenewablePotentialMW - safeGridInterconnectionCapacity);
        const totalPotentialUpgradeCost = requiredUpgradeMW * safeCostGridUpgradePerMW;

        // Annualize the upgrade cost over the project lifetime
        upgradeCostAnnualized = totalPotentialUpgradeCost / PROJECT_LIFETIME_YEARS;

        // For calculation simplicity, if economically viable, we consider integrating the full potential.
        // In reality, detailed studies would cap upgrades based on ROI, but for this index, viability enables full potential integration up to the physical limit.
        maxGridIntegrationMW = totalRenewablePotentialMW;
    }
    // If economic viability is not positive or no more potential than current grid, cap at existing interconnection or total potential.
    maxGridIntegrationMW = Math.min(maxGridIntegrationMW, totalRenewablePotentialMW);

    // --- 3. Calculate Annual Energy Contribution from Integrated Capacity ---
    let annualEnergyContributionMWh = 0;
    if (totalRenewablePotentialMW > 0 && maxGridIntegrationMW > 0) {
        // Calculate a blended capacity factor based on the proportion of solar/wind potential.
        const blendedCapacityFactor = (
            (solarPotentialCapacityMW * SOLAR_AVG_CAPACITY_FACTOR) + 
            (windPotentialCapacityMW * WIND_AVG_CAPACITY_FACTOR)
        ) / totalRenewablePotentialMW;
        annualEnergyContributionMWh = maxGridIntegrationMW * HOURS_IN_YEAR * blendedCapacityFactor;
    }
    // Ensure the energy contribution does not exceed the total physically possible from the raw potential.
    annualEnergyContributionMWh = Math.min(annualEnergyContributionMWh, totalRenewablePotentialEnergyMWh_yr);

    // --- 4. Calculate Net Economic Benefit (20-Year Lifetime) ---
    const totalRevenueOverLifetime = annualEnergyContributionMWh * (safeAvgRetailElectricityPrice + safePolicyIncentivePerMWh) * PROJECT_LIFETIME_YEARS;
    const totalGenerationCostOverLifetime = annualEnergyContributionMWh * safeAvgRenewableLCOE * PROJECT_LIFETIME_YEARS;
    const totalGridUpgradeCostOverLifetime = upgradeCostAnnualized * PROJECT_LIFETIME_YEARS; // This will be 0 if no upgrades were deemed viable/necessary.

    const netEconomicBenefit = totalRevenueOverLifetime - totalGenerationCostOverLifetime - totalGridUpgradeCostOverLifetime;

    // --- 5. Calculate Percentage Demand Met ---
    const percentageDemandMet = (annualEnergyContributionMWh / safeAnnualRegionalDemand) * 100;

    // --- 6. Calculate Grid Contribution Index (0-100) ---
    // Normalize each component to a 0-1 scale and apply weights.
    const MAX_DEMAND_MET_FOR_INDEX = 100; // Cap percentage demand met for normalization
    // A heuristic for max economic benefit: e.g., 50% of the total potential revenue from meeting demand for the entire lifetime.
    const MAX_ECONOMIC_BENEFIT_FOR_INDEX = safeAnnualRegionalDemand * safeAvgRetailElectricityPrice * PROJECT_LIFETIME_YEARS * 0.5;
    const MAX_GRID_INTEGRATION_FOR_INDEX = totalRenewablePotentialMW > 0 ? totalRenewablePotentialMW : 1; // Avoid division by zero

    const normalizedDemandMet = Math.min(1, Math.max(0, percentageDemandMet) / MAX_DEMAND_MET_FOR_INDEX);
    const normalizedEconomicBenefit = Math.min(1, Math.max(0, netEconomicBenefit) / MAX_ECONOMIC_BENEFIT_FOR_INDEX); // Only positive benefits contribute
    const normalizedGridReadiness = Math.min(1, Math.max(0, maxGridIntegrationMW) / MAX_GRID_INTEGRATION_FOR_INDEX);

    // Apply weights: 40% Demand Met, 30% Economic Benefit, 30% Grid Readiness
    const gridContributionIndex = (
        0.40 * normalizedDemandMet +
        0.30 * normalizedEconomicBenefit +
        0.30 * normalizedGridReadiness
    ) * 100;

    return {
        totalRenewablePotentialMW: parseFloat(totalRenewablePotentialMW.toFixed(2)),
        maxGridIntegrationMW: parseFloat(maxGridIntegrationMW.toFixed(2)),
        annualEnergyContributionMWh: parseFloat(annualEnergyContributionMWh.toFixed(0)),
        gridContributionIndex: parseFloat(gridContributionIndex.toFixed(1)),
        netEconomicBenefit: parseFloat(netEconomicBenefit.toFixed(0)),
        percentageDemandMet: parseFloat(percentageDemandMet.toFixed(1))
    };
}
